SELECT users.name, orders.id
FROM users
RIGHT JOIN orders ON users.id = orders.user_id;

const orders = [{id: 1, user_id: 100}, {id: 2, user_id: 200}];
const users = [{id: 100, name: 'Alice'}];
const right = orders.map(o => ({
  order_id: o.id,
  user_name: users.find(u => u.id === o.user_id)?.name || null
}));

List<Map> orders = List.of(
  Map.of("id", 1, "user_id", 100),
  Map.of("id", 2, "user_id", 200)
);
List<Map> users = List.of(Map.of("id", 100, "name", "Alice"));
